import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('log()', () => {
    it('should log a notification entry', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'delivered',
      });

      expect(entry.id).toBe('log-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.userId).toBe('user-1');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('welcome');
      expect(entry.status).toBe('delivered');
      expect(entry.timestamp).toBeInstanceOf(Date);
    });

    it('should generate sequential log IDs', () => {
      const entry1 = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'delivered',
      });
      const entry2 = historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'delivered',
      });

      expect(entry1.id).toBe('log-0001');
      expect(entry2.id).toBe('log-0002');
    });

    it('should log failed notifications with error', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'failed',
        error: 'No adapter registered',
      });

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('No adapter registered');
    });

    it('should log suppressed notifications', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order Confirmation',
        status: 'suppressed',
        error: 'Suppressed by user preferences',
      });

      expect(entry.status).toBe('suppressed');
      expect(entry.error).toBe('Suppressed by user preferences');
    });
  });

  describe('query()', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'delivered',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        userId: 'user-2',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order Confirmed',
        status: 'delivered',
        timestamp: new Date('2026-01-16T10:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0003',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'order-status-update',
        subject: 'Order Update',
        status: 'failed',
        error: 'Delivery failed',
        timestamp: new Date('2026-01-17T10:00:00Z'),
      });
    });

    it('should query by userId', () => {
      const results = historyService.query({ userId: 'user-1' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.userId === 'user-1')).toBe(true);
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'bob@example.com' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should query by date range', () => {
      const results = historyService.query({
        from: new Date('2026-01-16T00:00:00Z'),
        to: new Date('2026-01-17T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        userId: 'user-1',
        status: 'delivered',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({ userId: 'user-999' });
      expect(results).toHaveLength(0);
    });

    it('should return all entries with empty filter', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('convenience getters', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome!',
        status: 'delivered',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        userId: 'user-2',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order Confirmed',
        status: 'delivered',
        timestamp: new Date('2026-01-16T10:00:00Z'),
      });
    });

    it('should get by userId', () => {
      expect(historyService.getByUserId('user-1')).toHaveLength(1);
    });

    it('should get by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
    });

    it('should get by type', () => {
      expect(historyService.getByType('welcome')).toHaveLength(1);
    });

    it('should get by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-15T00:00:00Z'),
        new Date('2026-01-15T23:59:59Z'),
      );
      expect(results).toHaveLength(1);
    });

    it('should count logged entries', () => {
      expect(historyService.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when sent via event bus', async () => {
      const emailAdapter = new EmailAdapter({ defaultFrom: 'test@example.com' });
      notificationService.registerAdapter(emailAdapter);

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.getByUserId('user-1');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('welcome');
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should log failed notifications when no adapter registered', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.error).toContain('No adapter registered');
    });

    it('should log multiple notifications from different events', async () => {
      const emailAdapter = new EmailAdapter({ defaultFrom: 'test@example.com' });
      notificationService.registerAdapter(emailAdapter);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(historyService.count()).toBe(2);
      const logs = historyService.getByUserId('user-1');
      expect(logs).toHaveLength(2);
      const types = logs.map((l) => l.type).sort();
      expect(types).toEqual(['order-confirmation', 'welcome']);
    });

    it('should not log when history service is not set', async () => {
      const freshEventBus = new EventBus();
      const freshService = new NotificationService(freshEventBus);
      // No setHistoryService call

      await freshEventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as UserCreatedEvent);

      // The notification service still works
      expect(freshService.getNotificationCount()).toBe(1);
      // But nothing was logged to our history service
      expect(historyService.count()).toBe(0);
    });
  });
});

